import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Doctor } from './pages/Doctor';

const App = () => {
    const [userId, setUserId] = useState('');
    const [userName, setUserName] = useState('');
    const [medicineName, setMedicineName] = useState('');
    const [medicineInterval, setMedicineInterval] = useState(0);
    const [medicineDosage, setMedicineDosage] = useState(0);
    const [message, setMessage] = useState('');
    const [users, setUsers] = useState([]);
    const [loggedIn, setLoggedIn] = useState(false);
    const [doctorName, setDoctorName] = useState('');

    useEffect(() => {
        getUsers(); // Fetch users initially when the component mounts
        const usersInterval = setInterval(() => {
            getUsers(); // Setup interval to fetch users every second
        }, 1000);

        return () => clearInterval(usersInterval); // Cleanup the interval on component unmount
    }, []);

    useEffect(() => {
        const fingerprintInterval = setInterval(() => {
            checkFingerprint(); // Setup interval to check fingerprint every second
        }, 1000);

        return () => clearInterval(fingerprintInterval); // Cleanup the interval on component unmount
    }, [userId]); // Depend on userId to trigger re-check if it changes

    const getUsers = async () => {
        try {
            const response = await axios.get('http://192.168.1.83:3001/users');
            setUsers(response.data);
        } catch (error) {
            setMessage(error.response.data.message); // Display the error message from the server
        }
    };

    const checkFingerprint = async () => {
        try {
            const response = await axios.post('http://192.168.1.83:3001/check', { id: userId });

            console.log(response.data);

            if (response.data.isDoctor) {
                setLoggedIn(true);
                setDoctorName(response.data.name);
            }
            setMessage(`Fingerprint matched for user: ${response.data.name}`); // Access 'name' property from response data
        } catch (error) {
            if (error.response && error.response.status === 404) {
                setMessage('Fingerprint not matched');
            } else {
                setMessage(error.response.data.message); // Display the error message from the server
            }
        }
    };

    return (
        <div>
            {loggedIn ? (
                <div>
                    <Doctor doctorName={doctorName} />
                </div>
            ) : (
                <div>
                    <h2>Not a doctor</h2>
                </div>
            )}
        </div>
    );
};

export default App;
